public class ConcurrentTicketPurchase
{
    private readonly ApplicationDbContext _context;

    public ConcurrentTicketPurchase(ApplicationDbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var @event = await _context.Events.FindAsync(eventId);
        if (@event == null || @event.RemainingSeats < quantity) return false;

        var ticketsToAdd = Enumerable.Range(1, quantity).Select(seatNumber => new Ticket { EventId = eventId, SeatNumber = seatNumber, PurchaseDate = DateTime.UtcNow }).ToList();

        // Use RowVersion for optimistic concurrency
        var rowVersionBeforeUpdate = @event.RowVersion;

        foreach (var ticket in ticketsToAdd)
        {
            ticket.Event = @event;
            _context.Entry(@event).CurrentValues.SetValues(new Event { RemainingSeats = @event.RemainingSeats - quantity });
            _context.Entry(ticket).State = EntityState.Added;
        }

        try
        {
            await _context.SaveChangesAsync();

            // Update RowVersion after successful save to prevent other transactions from overwriting the changes
            @event.RowVersion = rowVersionBeforeUpdate.Increment(1);
            _context.Entry(@event).CurrentValues.SetValues(new Event { RemainingSeats = @event.RemainingSeats - quantity });
            await _context.SaveChangesAsync();
        }
        catch (DbUpdateConcurrencyException ex)
        {
            // If another transaction updated the event, reload it and try again
            var conflictEvent = await _context.Events.FindAsync(eventId);
            if (conflictEvent != null && conflictEvent.RowVersion == rowVersionBeforeUpdate)
            {
                return PurchaseTicketsAsync(eventId, quantity).ConfigureAwait(false);
            }
            else
            {
                throw; // Rethrow the exception to let the caller handle it
            }
        }

        return true;
    }
